import{c as s,cG as a,cb as i,c8 as n,cf as l,cT as e,ce as t}from"./chunks/framework.BlkIsu1j.js";const h=JSON.parse('{"title":"15. A 扩展：原子操作指令","description":"","frontmatter":{"title":"15. A 扩展：原子操作指令","outline":"deep","layout":"doc","prev":{"text":"14. M 扩展：乘除法指令","link":"/lang/assembly/14_m_extension"},"next":{"text":"16. F 与 D 扩展：浮点指令","link":"/lang/assembly/16_f_d_extension"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/15_a_extension.md","filePath":"lang/assembly/15_a_extension.md","lastUpdated":1780202472000}'),p={id:"frontmatter-title",tabindex:"-1"};const k=s({name:"lang/assembly/15_a_extension.md"},[["render",function(s,h,k,d,r,c){return a(),i("div",null,[n("h1",p,[l(e(s.$frontmatter.title)+" ",1),h[0]||(h[0]=n("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),h[1]||(h[1]=t('<p>单核时代，<code>load</code> → <code>add</code> → <code>store</code> 是流畅的。多核时代，两个 hart 同时执行同一条&quot;读-改-写&quot;逻辑，结果可能是一场灾难——两个 hart 都读到 0，都加 1，都写回 1；最终计数应该是 2，实际却是 1。A 扩展（Atomic Instructions）为此而生：提供硬件保证的不可分割操作，使多核并发编程成为可能。</p><h2 id="原子操作的意义" tabindex="-1">原子操作的意义 <a class="header-anchor" href="#原子操作的意义" aria-label="Permalink to “原子操作的意义”">​</a></h2><h3 id="问题-丢失的更新" tabindex="-1">问题：丢失的更新 <a class="header-anchor" href="#问题-丢失的更新" aria-label="Permalink to “问题：丢失的更新”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 两个 hart 同时执行这段代码，各调度一次：</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 初始值：counter = 0</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Hart A                          # Hart B</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ld   t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(s0)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = 0       ld   t0, 0(s0)    # t0 = 0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addi t0, t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # t0 = 1       addi t0, t0, 1    # t0 = 1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sd   t0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(s0)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # counter = 1  sd   t0, 0(s0)    # counter = 1 (!)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 最终 counter = 1，应该是 2</span></span></code></pre></div><p>这就是 read-modify-write 竞态（RMW race）。任何共享变量的读-改-写如果不被保护，在多核环境中都是不确定行为。保护方式有两种路线：</p><ol><li><strong>锁机制</strong>：临界区加锁，保证同一时刻只有一个 hart 进入——LR/SC 指令族</li><li><strong>无锁机制</strong>：将读-改-写本身原子化——AMO 指令族</li></ol><p>A 扩展同时提供这两种路线的硬件原语。它的设计范围包括：LR（Load-Reserved）、SC（Store-Conditional）、AMO（Atomic Memory Operation）、以及配套的 FENCE 内存屏障。</p><h2 id="lr-sc-load-reserved-store-conditional" tabindex="-1">LR/SC：Load-Reserved / Store-Conditional <a class="header-anchor" href="#lr-sc-load-reserved-store-conditional" aria-label="Permalink to “LR/SC：Load-Reserved / Store-Conditional”">​</a></h2><h3 id="基本原理" tabindex="-1">基本原理 <a class="header-anchor" href="#基本原理" aria-label="Permalink to “基本原理”">​</a></h3><p>LR 和 SC 是一对协作指令，共同实现&quot;如果自上次 LR 以来地址未被修改，则写入成功&quot;的语义：</p><ul><li><strong>LR</strong>：从地址加载值到寄存器，同时在该地址上设置一个硬件&quot;保留标记&quot;（reservation）</li><li><strong>SC</strong>：检查保留标记是否仍然有效。如果有效则将新值写入地址，并将 rd 设为 0（成功）；否则不执行写入，rd 设为非 0（失败）</li></ul><p>保留标记在以下条件中被清除：另一 hart 向保留地址写入、本 hart 的任何 store、或发生异常/中断。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lr.w rd, (rs1)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = MEM[rs1]; 对地址 rs1 设置保留标记</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lr.d rd, (rs1)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 64 位版本</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sc.w rd, rs2, (rs1)     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # if (保留标记有效) { MEM[rs1] = rs2; rd = 0; }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                          # </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { rd = 非零; }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sc.d rd, rs2, (rs1)     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 64 位版本</span></span></code></pre></div><p>LR 和 SC 的 opcode 均为 <code>0101111</code>（AMO 操作码）。LR 的 funct5=00010，SC 的 funct5=00011；funct3 指示宽度：010 为 .w（32 位），011 为 .d（64 位）。</p><h3 id="自旋锁-完整实现" tabindex="-1">自旋锁：完整实现 <a class="header-anchor" href="#自旋锁-完整实现" aria-label="Permalink to “自旋锁：完整实现”">​</a></h3><p>自旋锁是 LR/SC 的最经典应用——一个 hart 通过原子操作获取锁，其他 hart 忙等。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ---- 获取自旋锁 ----</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 锁变量的地址</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">spin_lock:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lr.w    t0, (a0)           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 原子读锁值，设保留</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bnez    t0, spin_lock      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 若锁已被持有(t0!=0)，忙等重试</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sc.w    t1, t1, (a0)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 尝试原子写 1 到锁地址</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bnez    t1, spin_lock      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # SC 失败？重试（保留标记被清除）</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 锁获取成功，进入临界区</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ---- 释放自旋锁 ----</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 锁变量的地址</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">spin_unlock:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sw      x0, (a0)           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 直接写 0 释放锁（不需要 SC——释放者是唯一的）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span></code></pre></div><p>几点关键观察：</p><ol><li><strong><code>lr.w t0, (a0)</code> 后的 <code>bnez t0, spin_lock</code></strong>：如果锁已被持有，不尝试 SC——这样避免不必要的写流量</li><li><strong>SC 后的 <code>bnez t1, spin_lock</code></strong>：即使 LR 读到 0、看起来锁自由，SC 仍可能失败——因为有另一个 hart 在我们的 LR 和 SC 之间也执行了写操作，清除了我们的保留标记</li><li><strong>释放用 <code>sw x0, (a0)</code> 而非 SC</strong>：只有锁持有者释放锁——这是已知的单写者，不需要原子条件保护</li></ol><h3 id="compare-and-swap-cas-实现" tabindex="-1">Compare-and-Swap（CAS）实现 <a class="header-anchor" href="#compare-and-swap-cas-实现" aria-label="Permalink to “Compare-and-Swap（CAS）实现”">​</a></h3><p>自旋锁是可串行化保护的一种方式，但无锁数据结构（如无锁栈、无锁队列）需要 CAS——比较并交换：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># CAS: 如果 MEM[a0] == a1，则 MEM[a0] = a2；返回旧值</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 参数: a0=地址, a1=期望值, a2=新值</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 返回: a0=0 成功, a0=1 失败</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cas:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lr.w    t0, (a0)           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = MEM[a0]（旧值），设保留</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bne     t0, a1, cas_fail   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 旧值 ≠ 期望值 → 失败</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sc.w    t0, a2, (a0)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 尝试写入 a2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bnez    t0, cas            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # SC 失败 → 重试</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      a0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 成功返回 0</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cas_fail:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li      a0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # 失败返回 1</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span></code></pre></div><p>这个 CAS 实现在 4 条指令内完成（不含 ret）——它的紧凑性使得编译器愿意将 CAS 内联到调用点，避免了函数调用开销。</p><h3 id="关键边界-lr-sc-对之间的限制" tabindex="-1">关键边界：LR/SC 对之间的限制 <a class="header-anchor" href="#关键边界-lr-sc-对之间的限制" aria-label="Permalink to “关键边界：LR/SC 对之间的限制”">​</a></h3><p>RISC-V 规范对 LR 和 SC 之间的指令有严格限制：</p><ul><li>只能执行基础整数指令（不能有 load/store、不能有跳转、不能有系统指令）</li><li>最大指令数由实现在 <code>mcontext</code> CSR 中约束（通常 16 条以内）</li><li>违反上述限制会导致 SC <strong>保证失败</strong></li></ul><p>规范这样写是为了避免硬件实现负担——LR/SC 间的指令越多，跟踪保留标记一致性的难度呈指数增长。实际使用中，LR 和 SC 之间通常只有 2-4 条指令（比较+分支），远在上述限制内。</p><h2 id="amo-指令族" tabindex="-1">AMO 指令族 <a class="header-anchor" href="#amo-指令族" aria-label="Permalink to “AMO 指令族”">​</a></h2><p>AMO（Atomic Memory Operation）将&quot;读-修改-写&quot;封装为单条指令——硬件保证其原子性和（通常的）内存顺序。</p><h3 id="指令总览" tabindex="-1">指令总览 <a class="header-anchor" href="#指令总览" aria-label="Permalink to “指令总览”">​</a></h3><table tabindex="0"><thead><tr><th>指令</th><th>funct5</th><th>语义</th></tr></thead><tbody><tr><td><code>amoswap.w/d</code></td><td>00001</td><td>原子交换：MEM = rs2，rd = 旧值</td></tr><tr><td><code>amoadd.w/d</code></td><td>00000</td><td>原子加：MEM += rs2，rd = 旧值</td></tr><tr><td><code>amoxor.w/d</code></td><td>00100</td><td>原子异或：MEM ^= rs2，rd = 旧值</td></tr><tr><td><code>amoand.w/d</code></td><td>01100</td><td>原子与：MEM &amp;= rs2，rd = 旧值</td></tr><tr><td><code>amoor.w/d</code></td><td>01000</td><td>原子或：MEM |= rs2，rd = 旧值</td></tr><tr><td><code>amomin.w/d</code></td><td>10000</td><td>有符号最小值：MEM = min(MEM, rs2)，rd = 旧值</td></tr><tr><td><code>amomax.w/d</code></td><td>10100</td><td>有符号最大值：MEM = max(MEM, rs2)，rd = 旧值</td></tr><tr><td><code>amominu.w/d</code></td><td>11000</td><td>无符号最小值</td></tr><tr><td><code>amomaxu.w/d</code></td><td>11100</td><td>无符号最大值</td></tr></tbody></table><p>所有 AMO 指令格式统一：<code>amo&lt;op&gt;.&lt;width&gt; rd, rs2, (rs1)</code>——从 <code>(rs1)</code> 读取旧值到 <code>rd</code>，将操作（旧值 op rs2）的结果写回 <code>(rs1)</code>。opcode 均为 <code>0101111</code>，funct3 区分宽度（010=.w, 011=.d）。</p><h3 id="无锁计数器" tabindex="-1">无锁计数器 <a class="header-anchor" href="#无锁计数器" aria-label="Permalink to “无锁计数器”">​</a></h3><p>计数器是 AMO 的最简单也是最高频应用：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 原子递增计数器</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 计数器地址</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">atomic_inc:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    amoadd.w t0, a1, (a0)      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = 旧值, MEM[a0] += 1</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                         # 调用者可选检查 t0（旧值）</span></span></code></pre></div><p>对比 LR/SC 版本需要 5-6 条指令，<code>amoadd</code> 一条指令完成——不仅代码更短，而且 pipeline 不会因 LR/SC 的重试循环而造成不可预测的延迟。</p><h3 id="无锁累加器-多生产者" tabindex="-1">无锁累加器（多生产者） <a class="header-anchor" href="#无锁累加器-多生产者" aria-label="Permalink to “无锁累加器（多生产者）”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 多个 hart 向共享累加器添加数据</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 累加器地址, a1 = 要增加的值</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">atomic_accumulate:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    amoadd.d x0, a1, (a0)      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 原子加 a1 到 MEM[a0]，丢弃旧值（写入 x0）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                         # 无返回值，纯副作用</span></span></code></pre></div><p>注意这里 <code>rd = x0</code>——我们只关心加法的副作用（更新累加器的值），对旧值不感兴趣。向 x0 写这是一种高效的值丢弃方式。</p><h3 id="无锁标志位设置" tabindex="-1">无锁标志位设置 <a class="header-anchor" href="#无锁标志位设置" aria-label="Permalink to “无锁标志位设置”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 原子设置标志位</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 标志地址, a1 = 要设置的位掩码</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">atomic_set_flags:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    amoor.w x0, a1, (a0)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 原子 OR 掩码到标志字，丢弃旧值</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 原子清除标志位</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">atomic_clear_flags:</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    not</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     t0, a1              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = ~a1（清除掩码）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    amoor.w x0, t0, (a0)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 等等——OR 不能清除位，应使用 AMOAND</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span></code></pre></div><p>等等——上例中清除标志的正确做法是 <code>amoand</code>，而非 <code>amoor</code>：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">atomic_clear_flags:</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    not</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     t0, a1              </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = ~a1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    amoand.w x0, t0, (a0)       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 原子 AND (~mask)，清除指定位</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span></code></pre></div><p>这个例子的要点是：选择 AMO 操作类型时需仔细匹配所需的修改语义。</p><h2 id="内存一致性模型" tabindex="-1">内存一致性模型 <a class="header-anchor" href="#内存一致性模型" aria-label="Permalink to “内存一致性模型”">​</a></h2><h3 id="rvwmo-概述" tabindex="-1">RVWMO 概述 <a class="header-anchor" href="#rvwmo-概述" aria-label="Permalink to “RVWMO 概述”">​</a></h3><p>RISC-V 采用 RVWMO（RISC-V Weak Memory Ordering）——一个宽松内存一致性模型。其核心规则：</p><ol><li><strong>同 hart 内的 load→load、store→store、load→store、store→load 地址依赖链保持顺序</strong>（同一 hart 看起来总是顺序执行的）</li><li><strong>不同 hart 之间的 load 和 store 可见顺序不保证一致</strong>——除非显式指定顺序约束</li><li><strong>AMO 和 LR/SC 固有 acquire 和/或 release 语义</strong></li></ol><h3 id="fence-指令" tabindex="-1">FENCE 指令 <a class="header-anchor" href="#fence-指令" aria-label="Permalink to “FENCE 指令”">​</a></h3><p><code>fence</code> 是汇编程序员强制执行内存顺序的工具：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fence iorw, iorw       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 最严格的 fence：所有前序访存完成后，后续访存才开始</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fence r, w             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 仅保证前序读完成后后续写才开始</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fence w, r             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 仅保证前序写完成后后续读才开始</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fence rw, rw           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 前后所有读写操作顺序化</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fence                  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 默认等价于 fence iorw, iorw</span></span></code></pre></div><p>前面的四字符表示<strong>前序操作集</strong>，后面的四字符表示<strong>后序操作集</strong>。每四个字符依次代表：i（输入设备）、o（输出设备）、r（读）、w（写）。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 自旋锁释放中常见模式</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 临界区操作...</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fence rw, w            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 保证临界区内的所有读写在锁释放前完成</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sw   x0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(s0)         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 释放锁</span></span></code></pre></div><h3 id="aq-rl-后缀-更细腻的顺序控制" tabindex="-1">.aq / .rl 后缀：更细腻的顺序控制 <a class="header-anchor" href="#aq-rl-后缀-更细腻的顺序控制" aria-label="Permalink to “.aq / .rl 后缀：更细腻的顺序控制”">​</a></h3><p>AMO 和 LR/SC 指令支持 <code>.aq</code>（acquire）和 <code>.rl</code>（release）后缀，提供比 <code>fence</code> 更精确的顺序约束：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lr.w.aq    t0, (a0)        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # LR with acquire: 后续访存不会重排到此 LR 之前</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sc.w.rl    t0, t1, (a0)    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # SC with release: 前序访存不会重排到此 SC 之后</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">amoswap.w.aqrl t0, t1, (a0)</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 同时 acquire + release（顺序一致性语义）</span></span></code></pre></div><p>不带后缀的 AMO/LR/SC 只保证原子性，不保证对其他访存的顺序约束。<code>.aq</code>/<code>.rl</code> 让程序员在需要时精确地&quot;拧紧&quot;顺序，而非对所有原子操作默认为最严格的顺序一致性——这是 RISC-V 在性能与可编程性之间的精妙平衡。</p><h3 id="fence-i-指令同步" tabindex="-1">FENCE.I：指令同步 <a class="header-anchor" href="#fence-i-指令同步" aria-label="Permalink to “FENCE.I：指令同步”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fence.i                </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 指令 fence：保证之前的 store 对后续取指可见</span></span></code></pre></div><p>当程序修改了自己的代码（JIT 编译、动态代码生成），必须在修改后、跳转到新代码前执行 <code>fence.i</code>。这在用户态汇编程序中少见，但对理解底层指令与数据的一致性至关重要。</p><h2 id="完整自旋锁-含顺序约束" tabindex="-1">完整自旋锁（含顺序约束） <a class="header-anchor" href="#完整自旋锁-含顺序约束" aria-label="Permalink to “完整自旋锁（含顺序约束）”">​</a></h2><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ---- 获取锁（带 acquire 语义）----</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 锁地址</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">acquire_lock:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    lr.w.aq  t0, (a0)         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # acquire: 临界区访存不会重排到此 LR 之前</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bnez     t0, acquire_lock  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 锁已被持，自旋</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    li       t1, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sc.w     t1, t1, (a0)     </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 尝试获取</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bnez     t1, acquire_lock  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 失败，重试</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 进入临界区</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ---- 释放锁（带 release 语义）----</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># a0 = 锁地址</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">release_lock:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    fence    rw, w             </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 先 fence: 临界区内所有读写完成</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    sw       x0, (a0)          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 再释放锁</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span></code></pre></div><p>这里的 <code>.aq</code> 后缀保证了关键的不变量：进入临界区后的任何访存不会被重排到 <code>lr.w</code> 之前——这意味着当 hart 看到锁已被我持有时，它一定也已经看到了锁持有者之前对临界区数据的修改。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>A 扩展提供 LR/SC（自旋锁、CAS）+ AMO（无锁计数、无锁数据结构）两类原子操作原语</li><li>LR 加载值并设保留标记，SC 仅在保留标记有效时写入——RLR（retry loop）是实现自旋锁的标准模式</li><li>AMO 将读-修改-写原子化为单条指令（amoswap/amoadd/amoxor/amoand/amoor/amomin/amomax），opcode=<code>0101111</code>，funct5 区分 9 种操作</li><li>RVWMO 是宽松内存一致性模型；<code>.aq</code>/<code>.rl</code> 后缀提供精确的 acquire/release 顺序控制，<code>fence</code> 指令是兜底的显式屏障</li><li>LR 与 SC 之间的指令受严格限制（无 load/store/跳转，通常 &lt;16 条指令）——保持这对指令间的序列短小是正确性的基本前提</li></ul>',65))])}]]);export{h as __pageData,k as default};
